+// appendPath replaces the trailing path of an RTSP URL with a custom path.
+func appendPath(baseURL, path string) string {
+	if path == "" {
+		return baseURL
+	}
+	if path[0] != '/' {
+		path = "/" + path
+	}
+	for i := len(baseURL) - 1; i >= 0; i-- {
+		if baseURL[i] == '/' {
+			return baseURL[:i] + path
+		}
+	}
+	return baseURL + path
+}
